mapper.select:
SELECT u.real_name AS userName, p.project_name AS projectName, t.task_name AS taskName, wr.work_content AS workContent, wr.hours AS hours, wr.work_date AS workDate FROM work_record wr LEFT JOIN sys_user u ON wr.user_id = u.id LEFT JOIN project p ON wr.project_id = p.id LEFT JOIN task t ON wr.task_id = t.id WHERE wr.del_flag = 0
AND wr.user_id = #{userId}
AND wr.project_id = #{projectId}
AND wr.work_date >= #{startDate}
AND wr.work_date <= #{endDate}
ORDER BY wr.work_date DESC
